  cadillac: ["CT4", "CT5", "Escalade", "Escalade ESV", "Lyriq", "XT4", "XT5", "XT6"],
  lincoln: ["Aviator", "Corsair", "Nautilus", "Navigator"],
  buick: ["Enclave", "Encore", "Encore GX", "Envision"],
